noncompliant:
public sealed class MySealedClass {
    protected string name = "Fred"; // Pointless protection level
    protected void SetName(string name) { }
}

sealed class ConfigManager {
    protected readonly string configPath; // Cannot be inherited
    protected virtual void LoadConfig() { } // Virtual is meaningless
}

compliant:
public sealed class MySealedClass {
    private string name = "Fred"; // Appropriate encapsulation
    public void SetName(string name) { this.name = name; }
}

sealed class ConfigManager {
    private readonly string configPath;
    internal void LoadConfig() { } // Or public if needed externally
}
